<style lang="scss" scoped>
.sp-filter-form {
  margin-bottom: 16px;
  padding-bottom: 0;
}
</style>
<template>
  <div>
    <div v-if="$route.path.indexOf('detail') === -1">
      <SpFilterForm :model="formQuery" @onSearch="onSearch" @onReset="onSearch">
        <SpFilterFormItem prop="name" label="團長姓名:">
          <el-input v-model="formQuery.name" placeholder="請輸入團長姓名" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="mobile" label="手機號碼:">
          <el-input v-model="formQuery.mobile" placeholder="請輸入團長手機號碼" />
        </SpFilterFormItem>
      </SpFilterForm>

      <el-tabs v-model="formQuery.approve_status" type="card" @tab-click="onSearch">
        <el-tab-pane
          v-for="item in stateList"
          :key="item.value"
          :label="item.title"
          :name="item.value"
        />

        <SpFinder
          ref="finder"
          no-selection
          :setting="setting"
          :hooks="{
            beforeSearch: beforeSearch,
            afterSearch: afterSearch
          }"
          url="/community/chief/apply/list"
        />
      </el-tabs>

      <SpDialog
        ref="resloveDialogRef"
        v-model="resloveDialog"
        :title="`審批`"
        :form="resloveForm"
        :form-list="resloveFormList"
        @onSubmit="onResloveSubmit"
      />
    </div>
    <router-view />
  </div>
</template>

<script>
import { createSetting } from '@shopex/finder'
import moment from 'moment'
export default {
  name: '',
  data() {
    return {
      formQuery: {
        name: '',
        mobile: '',
        approve_status: '-1'
      },
      stateList: [
        { title: '全部', value: '-1' },
        { title: '待審批', value: '0' }
      ],
      setting: createSetting({
        actions: [
          {
            name: '查看',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            action: {
              handler: ([row]) => {
                const { path } = this.$route
                this.$router.push({
                  path: `${path}/detail/${row.apply_id}`
                })
              }
            }
          },
          {
            name: '審批',
            key: 'apply',
            type: 'button',
            buttonType: 'text',
            visible: (row) => {
              return row.approve_status == '0'
            },
            action: {
              handler: async ([row]) => {
                this.resloveForm.apply_id = row.apply_id
                this.resloveDialog = true
              }
            }
          }
        ],
        columns: [
          { name: '團長', key: 'chief_name' },
          { name: '手機號碼', key: 'chief_mobile' },
          {
            name: '審批狀態',
            key: 'approve_status',
            render: (h, { row }) => h('span', {}, this.getApproveStatus(row.approve_status))
          },
          {
            name: '申請時間',
            key: 'created_at',
            render: (h, { row }) =>
              h('span', {}, moment(row.created_at * 1000).format('YYYY-MM-DD HH:mm:ss'))
          }
        ]
      }),
      resloveDialog: false,
      resloveForm: {
        apply_id: '',
        approve_status: 1,
        refuse_reason: ''
      },
      resloveFormList: [
        {
          label: '審批:',
          key: 'approve_status',
          type: 'radio',
          options: [
            { label: 1, name: '同意' },
            { label: 2, name: '不同意' }
          ],
          onChange: (e) => {
            if (e == 2) {
              this.resloveFormList[1].isShow = true
            } else {
              this.resloveFormList[1].isShow = false
            }
          }
        },
        {
          label: '拒絕原因:',
          key: 'refuse_reason',
          type: 'input',
          placeholder: '請輸入拒絕原因',
          isShow: false,
          validator: (rule, value, callback) => {
            if (this.resloveForm.approve_status == 2 && !value) {
              callback(new Error('不能為空'))
            } else {
              callback()
            }
          }
        }
      ]
    }
  },
  created() {},
  methods: {
    onSearch() {
      this.$refs.finder.refresh(true)
    },
    beforeSearch(params) {
      const formQuery = JSON.parse(JSON.stringify(this.formQuery))
      if (formQuery.approve_status == '-1') {
        delete formQuery.approve_status
      }
      return { ...params, ...formQuery }
    },
    afterSearch() {},
    async onResloveSubmit() {
      const { apply_id, approve_status, refuse_reason } = this.resloveForm
      await this.$api.community.approveChief(apply_id, {
        approve_status,
        refuse_reason
      })
      this.resloveDialog = false
      this.$refs.finder.refresh(true)
    },
    getApproveStatus(status) {
      if (status == '0') {
        return '未審核'
      } else if (status == '1') {
        return '已審核'
      } else if (status == '2') {
        return '已拒絕'
      }
    }
  }
}
</script>
